mapper.select:
SELECT c.*, c.status as auditStatus, c.is_excellent as isQuality, u.nickname as username, u.avatar as userAvatar, s.name as show_name FROM comment c LEFT JOIN sys_user u ON c.user_id = u.id LEFT JOIN `show` s ON c.show_id = s.id
c.deleted = 0
AND c.show_id = #{showId}
AND c.user_id = #{userId}
AND c.status = #{auditStatus}
AND (u.nickname LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%') OR c.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY c.is_excellent DESC, c.create_time DESC
